    if (bot.heldItem && matchesRequestedName(bot.heldItem, requested)) {
      return { item: bot.heldItem, slot: typeof bot.heldItem.slot === 'number' ? bot.heldItem.slot : 36 };
    }
    const entries = getAllSlotItems();
    for (let i = 0; i < entries.length; i += 1) {
      if (matchesRequestedName(entries[i].item, requested)) {
        return entries[i];
      }
    }
    return null;
  };
  const findBestMeleeWeapon = function () {
    const entries = getAllSlotItems();
    const heldSlot = bot.heldItem && typeof bot.heldItem.slot === 'number' ? bot.heldItem.slot : null;
    let best = null;
    for (let i = 0; i < entries.length; i += 1) {
      const score = getWeaponScore(entries[i].item);
      if (score > 0 && (!best || score > best.score || (score === best.score && entries[i].slot === heldSlot))) {
        best = { item: entries[i].item, slot: entries[i].slot, score: score };
      }
    }
    return best;
  };
  const preferredName = normalizeName(args.preferredWeapon);
  let selectedWeapon = null;
  let selectedByPreferred = false;
  if (preferredName) {
    selectedWeapon = findNamedItem(preferredName);
    selectedByPreferred = Boolean(selectedWeapon);
  }
  if (!selectedWeapon) {
    selectedWeapon = findBestMeleeWeapon();
    selectedByPreferred = false;
  }
  if (!selectedWeapon) {
    if (changes.length > 0) {
      return '<NO ITEM>: Updated available armor or hotbar items, but no preferred or melee weapon was available.';
    }
    return '<NO ITEM>: No preferred or melee weapon was available.';
  }
  const heldBeforeWeaponEquip = bot.heldItem;
  let weaponReady = false;
  if (heldBeforeWeaponEquip) {
    if (selectedByPreferred) {
      weaponReady = matchesRequestedName(heldBeforeWeaponEquip, preferredName);
    } else {
      weaponReady = getWeaponScore(heldBeforeWeaponEquip) > 0 && getWeaponScore(heldBeforeWeaponEquip) >= getWeaponScore(selectedWeapon.item);
    }
  }
  if (!weaponReady) {
    await equipItem(selectedWeapon, 'hand', selectedWeapon.item.displayName || selectedWeapon.item.name || 'weapon');
  }
  const foodNames = new Set(['apple', 'bread', 'cooked_beef', 'beef', 'cooked_porkchop', 'porkchop', 'cooked_chicken', 'chicken', 'cooked_mutton', 'mutton', 'cooked_cod', 'cod', 'cooked_salmon', 'salmon', 'baked_potato', 'potato', 'carrot', 'golden_carrot', 'melon_slice', 'pumpkin_pie', 'cookie', 'mushroom_stew', 'rabbit_stew', 'beetroot_soup', 'sweet_berries', 'glow_berries']);
  const isFoodItem = function (item) {
    const name = normalizeName(item && item.name);
    if (!name) { return false; }
    if (bot.registry && bot.registry.foodsByName && bot.registry.foodsByName[name]) { return true; }
    return foodNames.has(name);
  };
  const isBlockItem = function (item) {
    const name = normalizeName(item && item.name);
    if (!name) { return false; }
    if (bot.registry && bot.registry.blocksByName && bot.registry.blocksByName[name]) { return true; }
    return name.endsWith('_planks') || name.endsWith('_log') || name.endsWith('_wood') || name.endsWith('_stone') || name === 'dirt' || name === 'cobblestone' || name === 'sand' || name === 'gravel' || name === 'netherrack' || name === 'end_stone';
  };
  const isHotbarSlot = function (slot) {
    return slot >= 36 && slot <= 44;
  };
  const findHotbarMatching = function (predicate) {
    const slots = bot.inventory.slots || [];
    for (let slot = 36; slot <= 44; slot += 1) {
      const item = slots[slot];
      if (item && predicate(item)) {
        return slot;
      }
    }
    return null;
  };
  const isProtectedHotbarItem = function (item, slot) {
    const name = normalizeName(item && item.name);
    const heldSlot = bot.heldItem && typeof bot.heldItem.slot === 'number' ? bot.heldItem.slot : 36;
    if (slot === heldSlot) { return true; }
    if (isFoodItem(item) || isBlockItem(item)) { return true; }
    if (getWeaponScore(item) > 0) { return true; }
    return name === 'bow' || name === 'crossbow' || name === 'shield';
  };
  const ensureHotbarItem = async function (predicate, label) {
    if (findHotbarMatching(predicate) !== null) { return 'already'; }
    const entries = getAllSlotItems();
    let source = null;
    for (let i = 0; i < entries.length; i += 1) {
      if (!isHotbarSlot(entries[i].slot) && predicate(entries[i].item)) {
        source = entries[i];
        break;
      }
    }
    if (!source) { return 'missing'; }
    let destination = null;
    const slots = bot.inventory.slots || [];
    for (let slot = 36; slot <= 44; slot += 1) {
      if (!slots[slot]) {
        destination = slot;
        break;
      }
    }
    if (destination === null) {
      for (let slot = 36; slot <= 44; slot += 1) {
        const item = slots[slot];
        if (item && !isProtectedHotbarItem(item, slot)) {
          destination = slot;
          break;
        }
      }
    }
    if (destination === null) { return 'blocked'; }
    if (actions >= maxActions) {
      budgetHit = true;
      return 'limited';
    }
    try {
      await bot.moveSlotItem(source.slot, destination);
      actions += 1;
      changes.push(label + ' to hotbar');
      return 'moved';
    } catch (err) {
      failures.push(label + ' to hotbar');
      return 'failed';
    }
  };
  if (args.keepFoodAccessible) {
    await ensureHotbarItem(isFoodItem, 'food');
  }
  if (args.keepBlocksAccessible) {
    await ensureHotbarItem(isBlockItem, 'blocks');
  }
  if (budgetHit) {
    return '<STOPPED>: Reached the inventory action limit after ' + String(actions) + ' gear operation(s).';
  }
  if (changes.length === 0) {
    return '<STOPPED>: No gear changes were needed or possible from the current inventory.';
  }
  let summary = changes.slice(0, 6).join(', ');
  if (changes.length > 6) {
    summary += ', and ' + String(changes.length - 6) + ' more';
  }
  if (failures.length > 0) {
    return '<DONE>: Updated gear: ' + summary + '. Some optional changes failed.';
  }
  return '<DONE>: Updated gear: ' + summary + '.';
} catch (err) {
  return '<INVALID>: Could not equip gear from the current inventory state.';
}
